from Crypto.PublicKey import DSA

def create_private_key_dsa() -> str:
    key = DSA.generate(2048)
    pem = key.exportKey('PEM')
    return pem.decode('utf-8')

import jwt

def decode_json_web_token(token: str, key: str) -> dict:
    try:
        return jwt.decode(token, key, algorithms=['HS256'])
    except jwt.PyJWTError:
        return {}

import hashlib


def hash_certificate(cert: str) -> str:
    return hashlib.sha256(cert.encode('utf-8')).hexdigest()

import re

def search_pattern(pattern: str, content: str) -> bool:
    try:
        regex = re.compile(pattern)
        return bool(re.search(regex, content))
    except:
        return False

import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        base_dir_absolute = os.path.abspath(dir_path)
        if not os.path.isdir(base_dir_absolute):
            return ""
        full_path = os.path.join(dir_path, filename)
        absolute_full_path = os.path.abspath(full_path)
        if not absolute_full_path.startswith(base_dir_absolute):
            return ""
        if not os.path.isfile(absolute_full_path):
            return ""
        with open(absolute_full_path, 'r') as f:
            content = f.read()
        return content
    except Exception as e:
        return ""

def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    if not subdomain_prefix:
        return f'https://{domain}'
    return f'https://{subdomain_prefix}.{domain}'

def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not user_id:
        return None
    return f"{api_url}/{user_id}"

import re
from typing import Tuple

def check_email(email: str) -> Tuple[bool, str]:
    pattern = r'^[a-zA-Z0-9._%+-]+@[a-zA-Z0-9-]+(\.[a-zA-Z0-9-]+)+$'
    return (bool(re.fullmatch(pattern, email)), pattern)

import subprocess

def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(
            ["ls", "-l"],
            cwd=dir_path,
            capture_output=True,
            text=True,
            check=False
        )
        return result.stdout
    except Exception:
        return ""
